// Unchecked: não precisa de throws na assinatura, nem try/catch obrigatório
public class TopicNotFoundException extends RuntimeException {
    public TopicNotFoundException(String slug) {
        super("Tópico '" + slug + "' não encontrado");
    }
}

// Checked: compilador obriga a declarar throws (ou usar try/catch)
public void lerArquivoConfig() throws IOException {
    Files.readString(Path.of("config.properties"));
}

// try-with-resources: fecha o recurso automaticamente, mesmo se der exceção
try (BufferedReader leitor = new BufferedReader(new FileReader("dados.txt"))) {
    String linha = leitor.readLine();
    System.out.println(linha);
} catch (IOException e) {
    System.out.println("Erro ao ler arquivo: " + e.getMessage());
}
// leitor.close() foi chamado automaticamente aqui — não precisa de finally manual

// finally clássico: útil quando o recurso não implementa AutoCloseable
Conexao conexao = null;
try {
    conexao = abrirConexao();
    conexao.executar("SELECT 1");
} catch (SQLException e) {
    System.out.println("Falhou: " + e.getMessage());
} finally {
    if (conexao != null) {
        conexao.fechar(); // sempre executa, garante que a conexão não vaza
    }
}

codeExampleBad:
Conexao conexao = abrirConexao();
try {
    conexao.executar("SELECT 1"); // se isso lançar exceção...
} catch (SQLException e) {
    System.out.println("Erro");
}
// ...conexao.fechar() nunca é chamado! Faltou o finally (ou try-with-resources).
// Isso é um vazamento de recurso (connection leak) — cada request que passa por aqui
// deixa uma conexão aberta, até esgotar o pool.
